import { expect, test } from "bun:test";
import { canAccessProject } from "../src/permissions";

test("suspended users are denied edit even when they own the project", () => {
  const user = { id: "owner-a", orgId: "org-a", suspended: true, roles: [] };
  const project = { id: "project-a", orgId: "org-a", ownerId: "owner-a" };

  expect(canAccessProject({ user, project, action: "edit" })).toBe(false);
});

test("suspended users are denied read even when they are viewers", () => {
  const user = {
    id: "viewer-a",
    orgId: "org-a",
    suspended: true,
    roles: [{ role: "viewer", orgId: "org-a" }]
  };
  const project = { id: "project-a", orgId: "org-a", ownerId: "owner-a" };

  expect(canAccessProject({ user, project, action: "read" })).toBe(false);
});

import { expect, test } from "bun:test";
import { canAccessProject } from "../src/permissions";

test("explicit deny overrides owner edit permission", () => {
  const user = { id: "owner-a", orgId: "org-a", roles: [] };
  const project = { id: "project-a", orgId: "org-a", ownerId: "owner-a" };
  const policy = {
    denies: [{ userId: "owner-a", action: "edit", projectId: "project-a" }]
  };

  expect(canAccessProject({ user, project, action: "edit", policy })).toBe(false);
});

test("explicit deny overrides viewer read permission", () => {
  const user = {
    id: "viewer-a",
    orgId: "org-a",
    roles: [{ role: "viewer", orgId: "org-a" }]
  };
  const project = { id: "project-a", orgId: "org-a", ownerId: "owner-a" };
  const policy = {
    denies: [{ userId: "viewer-a", action: "read", orgId: "org-a" }]
  };

  expect(canAccessProject({ user, project, action: "read", policy })).toBe(false);
});

import { expect, test } from "bun:test";
import { canAccessProject } from "../src/permissions";

test("cross-org access is denied for admins", () => {
  const user = {
    id: "admin-a",
    orgId: "org-a",
    roles: [{ role: "admin", orgId: "org-b" }]
  };
  const project = { id: "project-b", orgId: "org-b", ownerId: "owner-b" };

  expect(canAccessProject({ user, project, action: "edit" })).toBe(false);
});

test("same-org access still works after cross-org restriction", () => {
  const owner = { id: "owner-a", orgId: "org-a", roles: [] };
  const admin = {
    id: "admin-a",
    orgId: "org-a",
    roles: [{ role: "admin", orgId: "org-a" }]
  };
  const project = { id: "project-a", orgId: "org-a", ownerId: "owner-a" };

  expect(canAccessProject({ user: owner, project, action: "edit" })).toBe(true);
  expect(canAccessProject({ user: admin, project, action: "edit" })).toBe(true);
});

import { expect, test } from "bun:test";
import { canAccessProject } from "../src/permissions";

test("valid temporary read grant allows read", () => {
  const user = { id: "temporary-reader-a", orgId: "org-a", roles: [] };
  const project = { id: "project-a", orgId: "org-a", ownerId: "owner-a" };
  const policy = {
    now: "2026-01-01T00:00:00.000Z",
    temporaryGrants: [
      {
        userId: "temporary-reader-a",
        projectId: "project-a",
        action: "read",
        expiresAt: "2026-01-02T00:00:00.000Z"
      }
    ]
  };

  expect(canAccessProject({ user, project, action: "read", policy })).toBe(true);
});

test("expired temporary grant denies access", () => {
  const user = { id: "temporary-reader-a", orgId: "org-a", roles: [] };
  const project = { id: "project-a", orgId: "org-a", ownerId: "owner-a" };
  const policy = {
    now: "2026-01-02T00:00:00.000Z",
    temporaryGrants: [
      {
        userId: "temporary-reader-a",
        projectId: "project-a",
        action: "read",
        expiresAt: "2026-01-01T00:00:00.000Z"
      }
    ]
  };

  expect(canAccessProject({ user, project, action: "read", policy })).toBe(false);
});

test("explicit deny overrides a valid temporary grant", () => {
  const user = { id: "temporary-reader-a", orgId: "org-a", roles: [] };
  const project = { id: "project-a", orgId: "org-a", ownerId: "owner-a" };
  const policy = {
    now: "2026-01-01T00:00:00.000Z",
    denies: [{ userId: "temporary-reader-a", action: "read", projectId: "project-a" }],
    temporaryGrants: [
      {
        userId: "temporary-reader-a",
        projectId: "project-a",
        action: "read",
        expiresAt: "2026-01-02T00:00:00.000Z"
      }
    ]
  };

  expect(canAccessProject({ user, project, action: "read", policy })).toBe(false);
});
